function calculate(num1, num2, operation) {
  if (operation === '+') {
    return num1 + num2;
  } else if (operation === '-') {
    return num1 - num2;
  } else if (operation === '*') {
    return num1 * num2;
  } else if (operation === '/') {
    if (num2 === 0) {
      return 'Cannot divide by zero!';
    }
    return num1 / num2;
  } else {
    return 'Invalid operation';
  }
}

// Test the calculator
console.log('5 + 3 =', calculate(5, 3, '+'));
console.log('10 - 4 =', calculate(10, 4, '-'));
console.log('6 * 7 =', calculate(6, 7, '*'));
console.log('20 / 4 =', calculate(20, 4, '/'));
console.log('15 / 0 =', calculate(15, 0, '/'));

